import logo from './logo.svg';
import './App.css';

import { useEffect, useState } from "react";

function App() {
  const [data, setData] = useState([]);

  useEffect(() => {
  fetch("http://localhost:8000/authentication/register/testuser", {
    method: "POST",
  })
    .then(res => res.json())
    .then(data => setData(data));
}, []);

  return (
    <div>
      <h1>My FastAPI Data</h1>
      <pre>{JSON.stringify(data, null, 2)}</pre>
    </div>
  );
}

export default App;
